(async () => {
  const reserved = new Set(['home', 'explore', 'notifications', 'messages', 'settings', 'compose', 'search', 'i']);
  const normalizeUser = (value) => {
    let user = String(value || '').trim();
    if (!user) return '';
    user = user.replace(/^@/, '');
    user = user.replace(/^https?:\/\/(?:www\.)?x\.com\//i, '');
    user = user.replace(/^\/+/, '');
    user = user.split('/')[0] || '';
    if (!/^[A-Za-z0-9_]{1,15}$/.test(user)) return '';
    if (reserved.has(user.toLowerCase())) return '';
    return user;
  };

  let username = normalizeUser(${{ args.username | json }});
  if (!username) {
    const resolveUser = () => {
      const profileHref = document.querySelector('a[data-testid="AppTabBar_Profile_Link"]')?.getAttribute('href');
      const fromProfileLink = normalizeUser(profileHref);
      if (fromProfileLink) return fromProfileLink;

      const switcherText = document.querySelector('[data-testid="SideNav_AccountSwitcher_Button"]')?.textContent || '';
      const switcherMatch = switcherText.match(/@([A-Za-z0-9_]{1,15})/);
      const fromSwitcher = normalizeUser(switcherMatch?.[1]);
      if (fromSwitcher) return fromSwitcher;

      for (const link of document.querySelectorAll('header a[href^="/"], nav a[href^="/"], aside a[href^="/"]')) {
        const fromNav = normalizeUser(link.getAttribute('href'));
        if (fromNav) return fromNav;
      }

      return '';
    };

    for (let i = 0; i < 10 && !username; i += 1) {
      username = resolveUser();
      if (!username) await new Promise(r => setTimeout(r, 1000));
    }
  }

  if (!username) throw new Error('Could not detect logged-in user');

  const ct0 = document.cookie.split(';').map(c => c.trim()).find(c => c.startsWith('ct0='))?.split('=')[1];
  if (!ct0) throw new Error('Not logged into x.com');
  const bearer = 'AAAAAAAAAAAAAAAAAAAAANRILgAAAAAAnNwIzUejRCOuH5E6I8xnZz4puTs%3D1Zv7ttfk8LF81IUq16cHjhLTvJu4FA33AGWWjCpTnA';
  const headers = {
    Authorization: 'Bearer ' + decodeURIComponent(bearer),
    'X-Csrf-Token': ct0,
    'X-Twitter-Auth-Type': 'OAuth2Session',
    'X-Twitter-Active-User': 'yes'
  };
  const variables = JSON.stringify({ screen_name: username, withSafetyModeUserFields: true });
  const features = JSON.stringify({
    responsive_web_graphql_exclude_directive_enabled: true,
    verified_phone_label_enabled: false,
    responsive_web_graphql_timeline_navigation_enabled: true
  });
  const queryId = 'qRednkZG-rn1P6b48NINmQ';
  const url = '/i/api/graphql/' + queryId + '/UserByScreenName?variables=' + encodeURIComponent(variables) + '&features=' + encodeURIComponent(features);
  const resp = await fetch(url, { headers, credentials: 'include' });
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  const d = await resp.json();
  const result = d.data?.user?.result;
  if (!result) throw new Error('User not found');
  const legacy = result.legacy || {};
  const expandedUrl = legacy.entities?.url?.urls?.[0]?.expanded_url || '';
  return [{
    screen_name: legacy.screen_name || username,
    name: legacy.name || '',
    bio: legacy.description || '',
    location: legacy.location || '',
    url: expandedUrl,
    followers: legacy.followers_count || 0,
    following: legacy.friends_count || 0,
    tweets: legacy.statuses_count || 0,
    verified: result.is_blue_verified || legacy.verified || false
  }];
})()
